target.echo:
@echo off setlocal set "SCRIPT_DIR=%~dp0" pushd "%SCRIPT_DIR%" >nul || ( echo Failed to enter application directory: "%SCRIPT_DIR%" pause exit /b 1 ) set "APP_HOME=%CD%" set "APP_JAR=%APP_HOME%\app\SimpleGenomeHub.jar" set "BUNDLED_JAVA=%APP_HOME%\runtime\bin\java.exe" set "TOOLS_DIR=%APP_HOME%\bin\tools\windows-x64" if not exist "%TOOLS_DIR%" set "TOOLS_DIR=%APP_HOME%\bin\tools" set "JAVA_EXE=" if exist "%BUNDLED_JAVA%" set "JAVA_EXE=%BUNDLED_JAVA%" if not defined JAVA_EXE if defined JAVA_HOME if exist "%JAVA_HOME%\bin\java.exe" set "JAVA_EXE=%JAVA_HOME%\bin\java.exe" if not defined JAVA_EXE set "JAVA_EXE=java"
if not exist "%APP_JAR%" ( echo Missing application jar: "%APP_JAR%" echo Current application directory: "%APP_HOME%" pause exit /b 1 )
if exist "%TOOLS_DIR%" set "PATH=%TOOLS_DIR%;%PATH%"
"%JAVA_EXE%" "-Dsimplegenomehub.app.home=%APP_HOME%" -cp "app\SimpleGenomeHub.jar;lib/*;tbtools/lib/*" simplegenomehub.gui.SimpleGenomeHubMainPanel set "EXIT_CODE=%ERRORLEVEL%" popd >nul if not "%EXIT_CODE%"=="0" ( echo. echo SimpleGenomeHub exited with code %EXIT_CODE%. echo App home: "%APP_HOME%" echo Java executable: "%JAVA_EXE%" if exist "%BUNDLED_JAVA%" ( echo Bundled runtime path: "%BUNDLED_JAVA%" ) else ( echo Bundled runtime path not found: "%BUNDLED_JAVA%" ) if exist "%TOOLS_DIR%" ( echo Tools path: "%TOOLS_DIR%" ) else ( echo Tools path not found: "%TOOLS_DIR%" ) echo If the package path contains unsupported characters, move it to a simple ASCII path and try again. pause ) exit /b %EXIT_CODE%

$ErrorActionPreference = "Stop"
$distDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$javaExe = Join-Path $distDir "runtime\bin\java.exe"
$toolsDir = Join-Path $distDir "bin\tools\windows-x64"
if (-not (Test-Path $toolsDir)) {
    $toolsDir = Join-Path $distDir "bin\tools"
}

if (-not (Test-Path $javaExe)) {
    if ($env:JAVA_HOME -and (Test-Path (Join-Path $env:JAVA_HOME "bin\java.exe"))) {
        $javaExe = Join-Path $env:JAVA_HOME "bin\java.exe"
    } else {
        $javaExe = "java"
    }
}

Push-Location $distDir
try {
    if (Test-Path $toolsDir) {
        $env:Path = $toolsDir + ";" + $env:Path
    }
    & $javaExe "-Dsimplegenomehub.app.home=$distDir" -cp "app\SimpleGenomeHub.jar;lib/*;tbtools/lib/*" simplegenomehub.gui.SimpleGenomeHubMainPanel
    exit $LASTEXITCODE
}
finally {
    Pop-Location
}

@echo off setlocal set "SCRIPT_DIR=%~dp0" pushd "%SCRIPT_DIR%" >nul || ( echo Failed to enter application directory: "%SCRIPT_DIR%" pause exit /b 1 ) set "APP_HOME=%CD%" set "APP_JAR=%APP_HOME%\app\SimpleGenomeHub.jar" set "BUNDLED_JAVA=%APP_HOME%\runtime\bin\java.exe" set "TOOLS_DIR=%APP_HOME%\bin\tools\windows-x64" set "JAVA_EXE=" if exist "%BUNDLED_JAVA%" set "JAVA_EXE=%BUNDLED_JAVA%" if not defined JAVA_EXE if defined JAVA_HOME if exist "%JAVA_HOME%\bin\java.exe" set "JAVA_EXE=%JAVA_HOME%\bin\java.exe" if not defined JAVA_EXE set "JAVA_EXE=java"
if not exist "%APP_JAR%" ( echo Missing application jar: "%APP_JAR%" pause exit /b 1 )
if exist "%TOOLS_DIR%" set "PATH=%TOOLS_DIR%;%PATH%"
"%JAVA_EXE%" "-Dsimplegenomehub.app.home=%APP_HOME%" -cp "app\SimpleGenomeHub.jar;lib/*;tbtools/lib/*" simplegenomehub.gui.SimpleGenomeHubMainPanel set "EXIT_CODE=%ERRORLEVEL%" popd >nul if not "%EXIT_CODE%"=="0" ( echo. echo SimpleGenomeHub exited with code %EXIT_CODE%. echo Java executable: "%JAVA_EXE%" echo Tools path: "%TOOLS_DIR%" pause ) exit /b %EXIT_CODE%

$ErrorActionPreference = "Stop"
$appHome = Split-Path -Parent $MyInvocation.MyCommand.Path
$javaExe = Join-Path $appHome "runtime\bin\java.exe"
$toolsDir = Join-Path $appHome "bin\tools\windows-x64"

if (-not (Test-Path $javaExe)) {
    if ($env:JAVA_HOME -and (Test-Path (Join-Path $env:JAVA_HOME "bin\java.exe"))) {
        $javaExe = Join-Path $env:JAVA_HOME "bin\java.exe"
    } else {
        $javaExe = "java"
    }
}

Push-Location $appHome
try {
    if (Test-Path $toolsDir) {
        $env:Path = $toolsDir + ";" + $env:Path
    }
    & $javaExe "-Dsimplegenomehub.app.home=$appHome" -cp "app\SimpleGenomeHub.jar;lib/*;tbtools/lib/*" simplegenomehub.gui.SimpleGenomeHubMainPanel
    exit $LASTEXITCODE
}
finally {
    Pop-Location
}
